mapper.select:
SELECT r.room_id AS roomId, r.room_name AS roomName, r.game_kind AS gameKind, r.round_count AS roundCount, r.room_status AS roomStatus, r.started_date AS startedDate, r.end_date AS endDate, CASE WHEN r.created_id = 1 THEN TRUE ELSE FALSE END AS isRoomMaster, CASE WHEN ru.user_id IS NOT NULL THEN TRUE ELSE FALSE END AS isPlayer FROM room r
LEFT JOIN room_users ru ON r.room_id = ru.room_id AND ru.user_id = #{userId}
WHERE ru.user_id IS NOT NULL OR r.created_id = #{userId}
ORDER BY r.started_date, r.end_date
